import pytest
from stringkit import reverse, count_vowels, title_case, starts_with_vowel


class TestReverse:
    def test_reverse_simple(self):
        assert reverse("hello") == "olleh"

    def test_reverse_empty(self):
        assert reverse("") == ""

    def test_reverse_single_char(self):
        assert reverse("a") == "a"

    def test_reverse_palindrome(self):
        assert reverse("racecar") == "racecar"

    def test_reverse_with_spaces(self):
        assert reverse("hello world") == "dlrow olleh"

    def test_reverse_unicode(self):
        assert reverse("café") == "éfac"


class TestCountVowels:
    def test_count_vowels_simple(self):
        assert count_vowels("hello") == 2

    def test_count_vowels_empty(self):
        assert count_vowels("") == 0

    def test_count_vowels_no_vowels(self):
        assert count_vowels("rhythms") == 0

    def test_count_vowels_uppercase(self):
        assert count_vowels("AEIOU") == 5

    def test_count_vowels_mixed_case(self):
        assert count_vowels("Hello World") == 3

    def test_count_vowels_special_chars(self):
        # Only a, e, i, o, u are vowels - digit 0 is not a vowel
        assert count_vowels("h3ll0 w0rld") == 0


class TestTitleCase:
    def test_title_case_simple(self):
        assert title_case("hello world") == "Hello World"

    def test_title_case_empty(self):
        assert title_case("") == ""

    def test_title_case_single_word(self):
        assert title_case("hello") == "Hello"

    def test_title_case_already_capped(self):
        assert title_case("HELLO WORLD") == "Hello World"

    def test_title_case_multiple_spaces(self):
        # str.split() collapses multiple spaces into one
        assert title_case("hello   world") == "Hello World"

    def test_title_case_mixed(self):
        assert title_case("hELLO wORLD") == "Hello World"


class TestStartsWithVowel:
    def test_starts_with_vowel_a(self):
        assert starts_with_vowel("apple") is True

    def test_starts_with_vowel_e(self):
        assert starts_with_vowel("egg") is True

    def test_starts_with_vowel_i(self):
        assert starts_with_vowel("ice") is True

    def test_starts_with_vowel_o(self):
        assert starts_with_vowel("orange") is True

    def test_starts_with_vowel_u(self):
        assert starts_with_vowel("umbrella") is True

    def test_starts_with_vowel_uppercase(self):
        assert starts_with_vowel("Apple") is True

    def test_starts_with_consonant(self):
        assert starts_with_vowel("banana") is False

    def test_starts_with_consonant_upper(self):
        assert starts_with_vowel("Banana") is False

    def test_starts_with_empty(self):
        assert starts_with_vowel("") is False

    def test_starts_with_number(self):
        assert starts_with_vowel("123abc") is False

